#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 1000
#define INF 1000000000

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (*x) - (*y);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, k, time;
        scanf("%d %d %d", &n, &k, &time);
        int TE[n], TM[n], TH[n], PE[n], PM[n], PH[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &TE[i], &TM[i], &TH[i]);
        }
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &PE[i], &PM[i], &PH[i]);
        }
        int dp[n + 1][time + 1];
        memset(dp, 0, sizeof(dp));
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= time; j++) {
                if (TE[i - 1] <= j) {
                    dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - TE[i - 1]] + PE[i - 1]);
                } else {
                    dp[i][j] = dp[i - 1][j];
                }
                if (TM[i - 1] <= j) {
                    dp[i][j] = max(dp[i][j], dp[i - 1][j - TM[i - 1]] + PM[i - 1]);
                }
                if (TH[i - 1] <= j) {
                    dp[i][j] = max(dp[i][j], dp[i - 1][j - TH[i - 1]] + PH[i - 1]);
                }
            }
        }
        printf("%d\n", dp[n][time]);
    }
    return 0;
}

