    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            int time = sc.nextInt();
            int[][] TE = new int[n][3];
            int[][] PE = new int[n][3];
            for (int i = 0; i < n; i++) {
                TE[i][0] = sc.nextInt();
                TE[i][1] = sc.nextInt();
                TE[i][2] = sc.nextInt();
            }
            for (int i = 0; i < n; i++) {
                PE[i][0] = sc.nextInt();
                PE[i][1] = sc.nextInt();
                PE[i][2] = sc.nextInt();
            }
            int[][] dp = new int[n + 1][time + 1];
            for (int i = 1; i <= n; i++) {
                for (int j = 1; j <= time; j++) {
                    if (TE[i - 1][0] <= j) {
                        dp[i][j] = Math.max(dp[i - 1][j], dp[i - 1][j - TE[i - 1][0]] + PE[i - 1][0]);
                    } else {
                        dp[i][j] = dp[i - 1][j];
                    }
                    if (TE[i - 1][1] <= j) {
                        dp[i][j] = Math.max(dp[i][j], dp[i - 1][j - TE[i - 1][1]] + PE[i - 1][1]);
                    }
                    if (TE[i - 1][2] <= j) {
                        dp[i][j] = Math.max(dp[i][j], dp[i - 1][j - TE[i - 1][2]] + PE[i - 1][2]);
                    }
                }
            }
            System.out.println(dp[n][time]);
        }
    }
}

